<?php
declare(strict_types=1);
if(!str_starts_with($path,'/admin/mailboxes'))return;
if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}

if($path==='/admin/mailboxes'&&$method==='POST'){
 verify_csrf();$id=(int)post('id');$isNew=$id===0;$action=(string)post('action');
 if($action==='delete'&&$id){db()->prepare('UPDATE email_mailboxes SET active=0,health_status=\'disabled\' WHERE id=?')->execute([$id]);audit('disable','email_mailbox',$id);flash('success','Mailbox disabled.');redirect('/admin/mailboxes');}
 $email=strtolower(trim((string)post('from_address')));$reply=trim((string)post('reply_to'));$host=trim((string)post('smtp_host'));
 if(!filter_var($email,FILTER_VALIDATE_EMAIL)||($reply!==''&&!filter_var($reply,FILTER_VALIDATE_EMAIL))||$host===''){flash('error','Enter a valid sender, optional reply-to address, and SMTP host.');redirect('/admin/mailboxes'.($id?'?edit='.$id:''));}
 $values=[trim((string)post('name')),trim((string)post('from_name')),$email,$reply?:null,$host,max(1,min(65535,(int)post('smtp_port'))),in_array(post('smtp_encryption'),['none','tls','ssl'],true)?post('smtp_encryption'):'tls',trim((string)post('smtp_username')),max(1,min(100000,(int)post('hourly_limit'))),max(1,min(1000000,(int)post('daily_limit'))),max(1,min(100,(int)post('weight'))),post('active')?1:0];
 try{if($id){$sql='UPDATE email_mailboxes SET name=?,from_name=?,from_address=?,reply_to=?,smtp_host=?,smtp_port=?,smtp_encryption=?,smtp_username=?,hourly_limit=?,daily_limit=?,weight=?,active=?,health_status=IF(?=1,IF(health_status=\'disabled\',\'healthy\',health_status),\'disabled\')';$args=array_merge($values,[$values[11]]);if(post('smtp_password')!==''){$sql.=',smtp_password_enc=?';$args[]=encrypt_secret((string)post('smtp_password'));}$sql.=' WHERE id=?';$args[]=$id;db()->prepare($sql)->execute($args);}else{db()->prepare('INSERT INTO email_mailboxes(name,from_name,from_address,reply_to,smtp_host,smtp_port,smtp_encryption,smtp_username,smtp_password_enc,hourly_limit,daily_limit,weight,active,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute(array_merge(array_slice($values,0,8),[encrypt_secret((string)post('smtp_password'))],array_slice($values,8),[user()['id']]));$id=(int)db()->lastInsertId();}audit($id?'update':'create','email_mailbox',$id,['from_address'=>$email]);
  if($action==='test'){try{crm_send_email(trim((string)post('test_email'))?:$email,app_setting('app_name','OpenCRM').' mailbox test','This mailbox is configured and can send email.',true);flash('success','Mailbox saved and test accepted for delivery.');}catch(Throwable $e){flash('error','Mailbox saved, but the test failed: '.$e->getMessage());}}else flash('success','Mailbox saved.');
 }catch(PDOException $e){flash('error','That sender address is already configured.');}redirect('/admin/mailboxes');
}
$edit=null;if((int)($_GET['edit']??0)){$q=db()->prepare('SELECT * FROM email_mailboxes WHERE id=?');$q->execute([(int)$_GET['edit']]);$edit=$q->fetch()?:null;}
$rows=db()->query("SELECT m.*,(SELECT COUNT(*) FROM email_mailbox_sends s WHERE s.mailbox_id=m.id AND s.status='sent' AND s.sent_at>=DATE_SUB(NOW(),INTERVAL 1 HOUR)) sent_hour,(SELECT COUNT(*) FROM email_mailbox_sends s WHERE s.mailbox_id=m.id AND s.status='sent' AND s.sent_at>=CURRENT_DATE) sent_day FROM email_mailboxes m ORDER BY m.active DESC,m.name")->fetchAll();
layout('Sending mailboxes',function()use($rows,$edit){?><div class="actions"><h1 style="margin:0">Sending mailboxes</h1><span class="spacer"></span><a class="btn secondary" href="/admin/mail">Default mail transport</a></div><div class="card"><p>OpenCRM distributes mail across healthy authenticated senders while honoring consent, suppressions, and mailbox limits. Use separate mailboxes for legitimate brands, teams, or workloadsâ€”not to bypass provider policies.</p></div><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="id" value="<?=e($edit['id']??'')?>"><h2><?=$edit?'Edit mailbox':'Add mailbox'?></h2><div class="form-grid"><label>Mailbox name<input name="name" value="<?=e($edit['name']??'')?>" required></label><label>From name<input name="from_name" value="<?=e($edit['from_name']??'')?>"></label><label>From email<input type="email" name="from_address" value="<?=e($edit['from_address']??'')?>" required></label><label>Reply-to<input type="email" name="reply_to" value="<?=e($edit['reply_to']??'')?>"></label><label>SMTP host<input name="smtp_host" value="<?=e($edit['smtp_host']??'')?>" required></label><label>Port<input type="number" name="smtp_port" value="<?=e($edit['smtp_port']??587)?>"></label><label>Encryption<select name="smtp_encryption"><?php foreach(['tls'=>'STARTTLS','ssl'=>'SSL/TLS','none'=>'None'] as $v=>$l):?><option value="<?=$v?>" <?=($edit['smtp_encryption']??'tls')===$v?'selected':''?>><?=$l?></option><?php endforeach?></select></label><label>Username<input name="smtp_username" value="<?=e($edit['smtp_username']??'')?>"></label><label>Password<input type="password" name="smtp_password" placeholder="<?=$edit?'Stored â€” leave blank to retain':'SMTP password'?>" <?=$edit?'':'required'?>></label><label>Hourly limit<input type="number" name="hourly_limit" min="1" value="<?=e($edit['hourly_limit']??100)?>"></label><label>Daily limit<input type="number" name="daily_limit" min="1" value="<?=e($edit['daily_limit']??500)?>"></label><label>Distribution weight<input type="number" name="weight" min="1" max="100" value="<?=e($edit['weight']??1)?>"></label><label><input style="width:auto" type="checkbox" name="active" value="1" <?=!isset($edit['active'])||$edit['active']?'checked':''?>> Active</label><label>Test recipient<input type="email" name="test_email"></label></div><div class="actions"><button name="action" value="save">Save mailbox</button><button class="secondary" name="action" value="test">Save and test</button><?php if($edit):?><a class="btn secondary" href="/admin/mailboxes">Cancel</a><?php endif?></div></form><div class="card"><h2>Mailbox pool</h2><table><thead><tr><th>Mailbox</th><th>Health</th><th>Usage</th><th>Limits</th><th>Last used</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['name'])?></strong><br><?=e($r['from_address'])?></td><td><?=e($r['active']?$r['health_status']:'disabled')?><?php if($r['last_error']):?><br><span class="danger-text"><?=e($r['last_error'])?></span><?php endif?></td><td><?=$r['sent_hour']?> this hour<br><?=$r['sent_day']?> today</td><td><?=$r['hourly_limit']?> / hour<br><?=$r['daily_limit']?> / day</td><td><?=e($r['last_used_at']?:'Never')?></td><td><a class="btn compact" href="?edit=<?=$r['id']?>">Edit</a></td></tr><?php endforeach?></tbody></table><?php if(!$rows):?><p class="muted">No pooled mailboxes configured. The default mail transport remains in use.</p><?php endif?></div><?php });exit;

